class TestDiscoverSessions:
    def test_discovers_session_from_fixture(self, tmp_sessions_dir):
        sessions = discover_sessions(sessions_dir=tmp_sessions_dir)
        assert len(sessions) == 1
        assert sessions[0].pid == 12345
        assert sessions[0].session_id == "aaaaaaaa-bbbb-cccc-dddd-eeeeeeeeeeee"
        assert sessions[0].cwd == "C:\\Users\\user\\source\\my-project"

    def test_returns_empty_for_missing_dir(self, tmp_path):
        sessions = discover_sessions(sessions_dir=tmp_path / "nonexistent")
        assert sessions == []

    def test_returns_empty_for_empty_dir(self, tmp_path):
        empty_dir = tmp_path / "sessions"
        empty_dir.mkdir()
        sessions = discover_sessions(sessions_dir=empty_dir)
        assert sessions == []

    def test_skips_malformed_json(self, tmp_path):
        sessions_dir = tmp_path / "sessions"
        sessions_dir.mkdir()
        (sessions_dir / "bad.json").write_text("not json{{{", encoding="utf-8")
        sessions = discover_sessions(sessions_dir=sessions_dir)
        assert sessions == []

    def test_skips_missing_fields(self, tmp_path):
        sessions_dir = tmp_path / "sessions"
        sessions_dir.mkdir()
        (sessions_dir / "1.json").write_text(
            json.dumps({"pid": 0, "sessionId": "", "cwd": "x", "startedAt": 0}),
            encoding="utf-8",
        )
        sessions = discover_sessions(sessions_dir=sessions_dir)
        assert sessions == []

    def test_orders_by_pid(self, tmp_path):
        sessions_dir = tmp_path / "sessions"
        sessions_dir.mkdir()
        for pid in [300, 100, 200]:
            data = {
                "pid": pid,
                "sessionId": f"session-{pid}",
                "cwd": f"/tmp/{pid}",
                "startedAt": 1000,
            }
            (sessions_dir / f"{pid}.json").write_text(json.dumps(data), encoding="utf-8")
        sessions = discover_sessions(sessions_dir=sessions_dir)
        pids = [s.pid for s in sessions]
        assert pids == [100, 200, 300]


class TestEncodeProjectKey:
    def test_windows_path(self):
        result = encode_project_key("C:\\Users\\user\\source\\my-project")
        assert result == "C--Users-user-source-my-project"

    def test_linux_path(self):
        result = encode_project_key("/home/user/source/my-project")
        assert result == "home-user-source-my-project"

    def test_forward_slash_path(self):
        result = encode_project_key("C:/Users/user/source/my-project")
        assert result == "C--Users-user-source-my-project"


class TestCwdRelativeToHome:
    def test_strips_home_prefix(self):
        from pathlib import Path

        home = str(Path.home()).replace("\\", "/")
        cwd = home + "/source/my-project"
        result = cwd_relative_to_home(cwd)
        assert result == "~/source/my-project"

    def test_preserves_non_home_paths(self):
        result = cwd_relative_to_home("/opt/somewhere/else")
        assert result == "/opt/somewhere/else"

    def test_strips_home_prefix_backslash(self):
        from pathlib import Path

        home = str(Path.home())
        cwd = home + "\\source\\project"
        result = cwd_relative_to_home(cwd)
        assert result == "~/source/project"


class TestValidatePid:
    @patch("claude_dashboard.session.psutil")
    def test_alive_claude_process(self, mock_psutil):
        mock_psutil.pid_exists.return_value = True
        mock_proc = MagicMock()
        mock_proc.name.return_value = "claude.exe"
        mock_psutil.Process.return_value = mock_proc
        assert validate_pid(1234) is True

    @patch("claude_dashboard.session.psutil")
    def test_alive_non_claude_process(self, mock_psutil):
        mock_psutil.pid_exists.return_value = True
        mock_proc = MagicMock()
        mock_proc.name.return_value = "python.exe"
        mock_psutil.Process.return_value = mock_proc
        assert validate_pid(1234) is False

    @patch("claude_dashboard.session.psutil")
    def test_dead_pid(self, mock_psutil):
        mock_psutil.pid_exists.return_value = False
        assert validate_pid(1234) is False

    @patch("claude_dashboard.session.psutil")
    def test_access_denied(self, mock_psutil):
        import psutil

        mock_psutil.pid_exists.return_value = True
        mock_psutil.Process.side_effect = psutil.AccessDenied(1234)
        mock_psutil.AccessDenied = psutil.AccessDenied
        mock_psutil.NoSuchProcess = psutil.NoSuchProcess
        assert validate_pid(1234) is False
